   100→// SubmitPlannerJob submits a planner job after a build failure
   101→func (h *jobSubmissionHelper) SubmitPlannerJob(ctx context.Context, config *TransflowConfig, buildError string, workspace string) (*PlanResult, error) {
   102→	// Check if this is a test submitter (backward compatibility)
   103→	if testSubmitter, ok := h.submitter.(interface {
   104→		SubmitAndWaitTerminal(ctx context.Context, spec JobSpec) (JobResult, error)
   105→	}); ok {
   106→		spec := JobSpec{
   107→			Name:    "planner",
   108→			Type:    "planner",
   109→			HCLPath: "", // Would be set from rendered assets
   110→			EnvVars: map[string]string{
   111→				"BUILD_ERROR": buildError,
   112→				"TARGET_REPO": config.TargetRepo,
   113→				"BASE_REF":    config.BaseRef,
   114→			},
   115→			Timeout: 15 * time.Minute,
   116→			Inputs: map[string]interface{}{
   117→				"workspace": workspace,
   118→			},
   119→		}
   120→
   121→		result, err := testSubmitter.SubmitAndWaitTerminal(ctx, spec)
   122→		if err != nil {
   123→			return nil, fmt.Errorf("planner job failed: %w", err)
   124→		}
   125→
   126→		// Parse the planner output
   127→		var planResult PlanResult
   128→		if err := json.Unmarshal([]byte(result.Output), &planResult); err != nil {
   129→			return nil, fmt.Errorf("failed to parse planner output: %w", err)
   130→		}
   131→
   132→		return &planResult, nil
   133→	}
   134→
   135→	// Production implementation using real Nomad job submission
   136→	if h.runner != nil {
   137→		// Step 1: Render planner assets
   138→		assets, err := h.runner.RenderPlannerAssets()
   139→		if err != nil {
   140→			return nil, fmt.Errorf("failed to render planner assets: %w", err)
   141→		}
   142→
   143→		// Step 2: Generate unique run ID for this planner job
   144→		runID := fmt.Sprintf("%s-planner-%d", config.ID, time.Now().Unix())
   145→
   146→		// Step 3: Substitute environment variables in HCL template
   147→		renderedHCLPath, err := substituteHCLTemplate(assets.HCLPath, runID)
   148→		if err != nil {
   149→			return nil, fmt.Errorf("failed to substitute HCL template: %w", err)
   150→		}
   151→
   152→		// Step 4: Submit job to Nomad and wait for completion
   153→		timeout := 15 * time.Minute
   154→		if err := orchestration.SubmitAndWaitTerminal(renderedHCLPath, timeout); err != nil {
   155→			return nil, fmt.Errorf("planner job failed: %w", err)
   156→		}
   157→
   158→		// Step 5: Read and parse job output artifact
   159→		// The planner job should write plan.json to the output directory
   160→		artifactPath := filepath.Join(workspace, "planner", "out", "plan.json")
   161→		var planResult PlanResult
   162→		if err := readJobArtifact(artifactPath, &planResult); err != nil {
   163→			return nil, fmt.Errorf("failed to read planner output: %w", err)
   164→		}
   165→
   166→		return &planResult, nil
   167→	}
   168→
   169→	// No runner provided and not a test submitter
   170→	return nil, fmt.Errorf("no production runner or test submitter available for job submission")
   171→}
