   173→// SubmitReducerJob submits a reducer job to determine the next action
   174→func (h *jobSubmissionHelper) SubmitReducerJob(ctx context.Context, planID string, results []BranchResult, winner *BranchResult, workspace string) (*NextAction, error) {
   175→	// Check if this is a test submitter (backward compatibility)
   176→	if testSubmitter, ok := h.submitter.(interface {
   177→		SubmitAndWaitTerminal(ctx context.Context, spec JobSpec) (JobResult, error)
