   179→		spec := JobSpec{
   180→			Name:    "reducer",
   181→			Type:    "reducer",
   182→			HCLPath: "", // Would be set from rendered assets
   183→			EnvVars: map[string]string{
   184→				"PLAN_ID": planID,
   185→			},
   186→			Timeout: 10 * time.Minute,
   187→			Inputs: map[string]interface{}{
   188→				"workspace": workspace,
   189→				"results":   results,
   190→				"winner":    winner,
   191→			},
   192→		}
   193→
   194→		result, err := testSubmitter.SubmitAndWaitTerminal(ctx, spec)
   195→		if err != nil {
   196→			return nil, fmt.Errorf("reducer job failed: %w", err)
   197→		}
   198→
   199→		// Parse the reducer output
   200→		var nextAction NextAction
