   202→			return nil, fmt.Errorf("failed to parse reducer output: %w", err)
   203→		}
   204→
   205→		return &nextAction, nil
   206→	}
   207→
   208→	// Production implementation using real Nomad job submission
   209→	if h.runner != nil {
   210→		// Step 1: Render reducer assets
   211→		assets, err := h.runner.RenderReducerAssets()
   212→		if err != nil {
   213→			return nil, fmt.Errorf("failed to render reducer assets: %w", err)
   214→		}
   215→
   216→		// Step 2: Generate unique run ID for this reducer job
   217→		runID := fmt.Sprintf("%s-reducer-%d", planID, time.Now().Unix())
   218→
   219→		// Step 3: Substitute environment variables in HCL template
   220→		renderedHCLPath, err := substituteHCLTemplate(assets.HCLPath, runID)
   221→		if err != nil {
   222→			return nil, fmt.Errorf("failed to substitute HCL template: %w", err)
   223→		}
   224→
   225→		// Step 4: Submit job to Nomad and wait for completion
   226→		timeout := 10 * time.Minute
   227→		if err := orchestration.SubmitAndWaitTerminal(renderedHCLPath, timeout); err != nil {
   228→			return nil, fmt.Errorf("reducer job failed: %w", err)
   229→		}
   230→
   231→		// Step 5: Read and parse job output artifact
   232→		// The reducer job should write next.json to the output directory
   233→		artifactPath := filepath.Join(workspace, "reducer", "out", "next.json")
   234→		var nextAction NextAction
   235→		if err := readJobArtifact(artifactPath, &nextAction); err != nil {
   236→			return nil, fmt.Errorf("failed to read reducer output: %w", err)
   237→		}
   238→
   239→		return &nextAction, nil
   240→	}
   241→
   242→	// No runner provided and not a test submitter
   243→	return nil, fmt.Errorf("no production runner or test submitter available for job submission")
   244→}
